import React from "react"
import { Link } from "gatsby"
import { FaGithub, FaLinkedin, FaEnvelope } from "react-icons/fa"
import "../styles/Navigation.scss"
import { getClientDimensions, replaceAll } from "../utils/helpers"

const activeStile = { color: "rgba(243, 159, 255, 0.9)" }

class Navigation extends React.Component {

    constructor(props) {
        super(props)
        this.state = { headerMessage: "Radu" }
        this.me = null
    }


    componentDidMount() {
        window.onscroll = this.handleScroll
        this.me = document.getElementById("me")
        let p = window.location.pathname.split("/")
        if (p[0] === "" && p[1] === "") {
            this.setState({ headerMessage: "Radu" })
        } else {
            const candidate = p.length >= 2 ? p[p.length - 2] : ''
            if (!candidate) {
                this.setState({ headerMessage: 'Radu' })
                return
            }
            let m = candidate.split("")
            if (m.length === 0) {
                this.setState({ headerMessage: 'Radu' })
                return
            }
            m[0] = m[0].toUpperCase()
            let final = replaceAll(m.join(""), "-", " ")

            let dim = getClientDimensions()

            if (dim.width < dim.height && final.length > dim.width / 10) {
                final = final.substring(0, dim.width / 10) + "... "
            }

            this.setState({ headerMessage: final })
        }
    }

    handleScroll = () => {
        if (document.body.scrollTop > 50 || document.documentElement.scrollTop > 50) {
            document.getElementById("navigation").classList.add("nav_idle")
            document.getElementById("header").classList.add("header_hidden")
            if (this.me) {
                document.getElementById("me").classList.add("get_down")
            }
        } else {
            document.getElementById("navigation").classList.remove("nav_idle")
            document.getElementById("header").classList.remove("header_hidden")
            if (this.me) {
                document.getElementById("me").classList.remove("get_down")
            }
        }
    }

    render() {
        return (
            <div className="main_div">
                <nav className="navigation" id='navigation'>
                    <Link to="/" aria-label="Logo, click to navigate to the home page"
                        style={{ height: "90%" }}>
                        <div className="nav_logo" id="navLogo">Radu</div>
                    </Link>
                    <Link to="/" activeStyle={activeStile} className="nav_link">
                        <span>Home</span>
                    </Link>
                    <Link to="/portfolio/" activeStyle={activeStile} className="nav_link">
                        <span>Portfolio</span>
                    </Link>
                    <Link to="/blog/" activeStyle={activeStile} className="nav_link">
                        <span>Blog</span>
                    </Link>

                    <div className="right_nav">
                        <a href="https://github.com/raduorleanu" aria-label="My github profile"> <FaGithub /> </a>
                        <a href="https://www.linkedin.com/in/radu-gabriel-orleanu/" aria-label="Mi LinkedIn profile"> <FaLinkedin /> </a>
                        <a href="mailto:raduorleanu@gmail.com" aria-label="send me an email"> <FaEnvelope /> </a>
                    </div>
                </nav>
                <header id="header" className='header_default'> {this.state.headerMessage} </header>
            </div>
        )
    }
}

export default Navigation
